xpath.script:
(function () {
    'use strict';
    // _auctionLbPoll is exposed by the base template's IIFE.
    // Calling it every 2 s keeps current_bid / current_bid_team updated
    // twice as fast as the base 4 s poll, without duplicating any render logic.
    setInterval(function () {
        if (typeof window._auctionLbPoll === 'function') {
            window._auctionLbPoll();
        }
    }, 2000);
})();
